import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as i,e as r}from"./app-be253e4c.js";const d={},t=r('<h1 id="组合模式" tabindex="-1"><a class="header-anchor" href="#组合模式" aria-hidden="true">#</a> 组合模式</h1><p>组合模式<code>Composite Pattern</code>又叫部分整体模式，是用于把一组相似的对象当作一个单一的对象，通常依据树形结构来组合对象，用来表示部分以及整体层次，这种类型的设计模式属于结构型模式，它创建了对象组的树形结构。</p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>在软件工程中，组合模式是一种分区设计模式，组合模式描述了将以与对象的单个实例相同的方式对待一组对象，组合的目的是将对象组成树状结构，以表示整个部分的层次结构。即将对象组合成树形结构以表示部分-整体的层次结构，使得用户对单个对象和组合对象的使用具有一致性，通常用于树形菜单、文件、文件夹、表单的管理等。</p><h3 id="优点" tabindex="-1"><a class="header-anchor" href="#优点" aria-hidden="true">#</a> 优点</h3><ul><li>高层模块调用简单。</li><li>节点自由增加。</li><li>忽略组合对象和单个对象的差别，对外一致接口使用。</li></ul><h3 id="缺点" tabindex="-1"><a class="header-anchor" href="#缺点" aria-hidden="true">#</a> 缺点</h3><ul><li>树叶对象接口一致，无法区分，只有在运行时方可辨别。</li><li>包裹对象创建太多，额外增加内存负担。</li><li>在使用组合模式时，其叶子和树枝的声明都是实现类而不是接口，违反了依赖倒置原则。</li></ul><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2>',9),h=[t];function o(c,l){return a(),i("div",null,h)}const _=e(d,[["render",o],["__file","composite-mode.html.vue"]]);export{_ as default};
